import { db } from './db';

/**
 * Search users and posts by query string
 * Current implementation: Full table scan on every query
 */
export async function search(query: string, limit: number = 20) {
  const results: any[] = [];

  // SLOW: Query 1 - Full table scan (no index)
  const users = await db.query(
    `SELECT * FROM users 
     WHERE name ILIKE '%${query}%' 
     OR email ILIKE '%${query}%'`
  );
  results.push(...users.rows.map(u => ({ type: 'user', ...u })));

  // SLOW: Query 2 - JOIN with no optimization
  const posts = await db.query(
    `SELECT p.*, u.name as author_name
     FROM posts p
     JOIN users u ON p.user_id = u.id
     WHERE p.content ILIKE '%${query}%'
     OR p.title ILIKE '%${query}%'`
  );
  results.push(...posts.rows.map(p => ({ type: 'post', ...p })));

  // SLOW: Query 3 - N+1 query for tags
  for (const post of posts.rows.slice(0, 10)) {
    const tags = await db.query(
      `SELECT t.name FROM tags t
       JOIN post_tags pt ON t.id = pt.tag_id
       WHERE pt.post_id = '${post.id}'`
    );
    post.tags = tags.rows.map(t => t.name);
  }

  return results.slice(0, limit);
}

/**
 * Get trending posts (used on homepage)
 * Current implementation: Complex aggregation on every request
 */
export async function getTrendingPosts(limit: number = 10) {
  // SLOW: Full aggregation without materialized view
  return await db.query(`
    SELECT 
      p.id, p.title, p.content, p.created_at,
      u.name as author_name,
      COUNT(l.id) as like_count,
      COUNT(c.id) as comment_count
    FROM posts p
    JOIN users u ON p.user_id = u.id
    LEFT JOIN likes l ON p.id = l.post_id
    LEFT JOIN comments c ON p.id = c.post_id
    WHERE p.created_at > NOW() - INTERVAL '7 days'
    GROUP BY p.id, u.name
    ORDER BY like_count DESC, comment_count DESC
    LIMIT ${limit}
  `);
}

